     1→#!/usr/bin/env bun
     2→/**
     3→ * MMS Parallel Harness Runner
     4→ *
     5→ * Executes features in parallel using git worktrees.
     6→ * Each worktree runs an isolated Claude session.
     7→ *
     8→ * Usage:
     9→ *   bun scripts/parallel-runner.ts           # Interactive mode
    10→ *   bun scripts/parallel-runner.ts wave 1    # Execute wave 1
    11→ *   bun scripts/parallel-runner.ts status    # Show current status
    12→ *   bun scripts/parallel-runner.ts cleanup   # Remove all worktrees
    13→ */
    14→
    15→import { spawn } from 'child_process';
    16→import { waves, getEstimatedSpeedup, getBranchName, getWorktreePath, type ParallelWave, type ParallelGroup } from './parallel-config';
    17→
    18→// ─────────────────────────────────────────────────────────────────────────────
    19→// COLORS
    20→// ─────────────────────────────────────────────────────────────────────────────
    21→
    22→const c = {
    23→  reset: '\x1b[0m',
    24→  bold: '\x1b[1m',
    25→  dim: '\x1b[2m',
    26→  red: '\x1b[31m',
    27→  green: '\x1b[32m',
    28→  yellow: '\x1b[33m',
    29→  blue: '\x1b[34m',
    30→  magenta: '\x1b[35m',
    31→  cyan: '\x1b[36m',
    32→};
    33→
    34→function print(msg: string) {
