    77→// ─────────────────────────────────────────────────────────────────────────────
    78→// GIT WORKTREE MANAGEMENT
    79→// ─────────────────────────────────────────────────────────────────────────────
    80→
    81→async function runCommand(cmd: string, args: string[], cwd?: string): Promise<{ stdout: string; stderr: string; exitCode: number }> {
    82→  const proc = Bun.spawn([cmd, ...args], {
    83→    cwd: cwd ?? process.cwd(),
    84→    stdout: 'pipe',
    85→    stderr: 'pipe',
    86→  });
    87→
    88→  const stdout = await new Response(proc.stdout).text();
    89→  const stderr = await new Response(proc.stderr).text();
    90→  const exitCode = await proc.exited;
    91→
    92→  return { stdout, stderr, exitCode };
    93→}
    94→
    95→async function createWorktree(featureId: string): Promise<boolean> {
    96→  const branchName = getBranchName(featureId);
    97→  const worktreePath = getWorktreePath(featureId);
    98→
    99→  printInfo(`Creating worktree for ${featureId}...`);
   100→
   101→  // Check if worktree already exists
   102→  const { stdout: worktreeList } = await runCommand('git', ['worktree', 'list']);
   103→  if (worktreeList.includes(worktreePath)) {
   104→    printWarning(`Worktree ${worktreePath} already exists`);
   105→    return true;
   106→  }
   107→
   108→  // Check if branch exists
   109→  const { exitCode: branchExists } = await runCommand('git', ['rev-parse', '--verify', branchName]);
   110→
   111→  if (branchExists === 0) {
   112→    // Branch exists, create worktree with existing branch
   113→    const { exitCode, stderr } = await runCommand('git', ['worktree', 'add', worktreePath, branchName]);
   114→    if (exitCode !== 0) {
   115→      printError(`Failed to create worktree: ${stderr}`);
   116→      return false;
   117→    }
   118→  } else {
   119→    // Create new branch from main
   120→    const { exitCode, stderr } = await runCommand('git', ['worktree', 'add', '-b', branchName, worktreePath, 'main']);
   121→    if (exitCode !== 0) {
   122→      printError(`Failed to create worktree with new branch: ${stderr}`);
   123→      return false;
   124→    }
   125→  }
   126→
   127→  printSuccess(`Created worktree ${worktreePath} on branch ${branchName}`);
   128→  return true;
   129→}
   130→
   131→async function removeWorktree(featureId: string): Promise<boolean> {
   132→  const worktreePath = getWorktreePath(featureId);
   133→
   134→  printInfo(`Removing worktree ${worktreePath}...`);
   135→
   136→  const { exitCode, stderr } = await runCommand('git', ['worktree', 'remove', worktreePath, '--force']);
   137→  if (exitCode !== 0 && !stderr.includes('is not a working tree')) {
   138→    printError(`Failed to remove worktree: ${stderr}`);
   139→    return false;
   140→  }
   141→
   142→  printSuccess(`Removed worktree ${worktreePath}`);
   143→  return true;
   144→}
   145→
   146→async function listWorktrees(): Promise<string[]> {
   147→  const { stdout } = await runCommand('git', ['worktree', 'list']);
   148→  return stdout.split('\n').filter(Boolean);
   149→}
