   151→// ─────────────────────────────────────────────────────────────────────────────
   152→// FEATURE STATUS
   153→// ─────────────────────────────────────────────────────────────────────────────
   154→
   155→async function getFeatureStatus(featureId: string): Promise<'pending' | 'complete' | 'in-progress'> {
   156→  try {
   157→    const file = Bun.file('features.json');
   158→    const data = await file.json();
   159→    const feature = data.features?.find((f: { id: string }) => f.id === featureId);
   160→
   161→    if (!feature) return 'pending';
   162→    if (feature.passes === true) return 'complete';
   163→
   164→    // Check if worktree exists (in-progress)
   165→    const worktreePath = getWorktreePath(featureId);
   166→    const { stdout } = await runCommand('git', ['worktree', 'list']);
   167→    if (stdout.includes(worktreePath)) return 'in-progress';
   168→
   169→    return 'pending';
   170→  } catch {
   171→    return 'pending';
   172→  }
   173→}
