   175→// ─────────────────────────────────────────────────────────────────────────────
   176→// CLAUDE SESSION MANAGEMENT
   177→// ─────────────────────────────────────────────────────────────────────────────
   178→
   179→interface ClaudeSession {
   180→  featureId: string;
   181→  process: ReturnType<typeof spawn>;
   182→  startTime: Date;
   183→}
   184→
   185→const activeSessions: Map<string, ClaudeSession> = new Map();
   186→
   187→function getIsolationPrompt(featureId: string, groupName: string): string {
   188→  return `You are working on feature ${featureId} in the MMS project.
   189→
   190→━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   191→🎯 FEATURE: ${featureId}
   192→📦 GROUP: ${groupName}
   193→━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   194→
   195→📋 HARNESS PROTOCOL (PARALLEL MODE)
   196→━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   197→
   198→1. READ claude-progress.txt → current state
   199→2. READ features.json → find ${featureId} details
   200→3. IMPLEMENT ONLY ${featureId} (do not touch other features)
   201→4. TEST visually with Playwright MCP
   202→5. UPDATE features.json → set ${featureId} passes: true
   203→6. UPDATE claude-progress.txt → add session notes
   204→7. COMMIT changes with message: feat(canvas): ${featureId} - <description>
   205→
   206→⚠️  IMPORTANT: This is a PARALLEL execution. Other features are being
   207→worked on simultaneously in other worktrees. DO NOT modify files
   208→outside the scope of ${featureId}.
   209→
   210→━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━
   211→When done with ${featureId}, type /exit to complete this session.
   212→━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━`;
   213→}
   214→
   215→async function startClaudeSession(featureId: string, groupName: string, worktreePath: string): Promise<void> {
   216→  const isolationPrompt = getIsolationPrompt(featureId, groupName);
   217→  const absolutePath = `${process.cwd()}/${worktreePath}`;
   218→
   219→  printInfo(`Starting Claude session for ${featureId} in ${worktreePath}...`);
   220→
   221→  // Create a new terminal window for each Claude session (macOS)
   222→  const script = `
   223→    tell application "Terminal"
   224→      do script "cd '${absolutePath}' && ci --append-system-prompt '${isolationPrompt.replace(/'/g, "'\\''")}'"
   225→      activate
   226→    end tell
   227→  `;
   228→
   229→  const proc = spawn('osascript', ['-e', script], {
   230→    detached: true,
   231→    stdio: 'ignore',
   232→  });
   233→
   234→  proc.unref();
   235→
   236→  activeSessions.set(featureId, {
   237→    featureId,
   238→    process: proc,
   239→    startTime: new Date(),
   240→  });
   241→
   242→  printSuccess(`Claude session started for ${featureId}`);
   243→  await notify('🚀 Parallel Harness', `Started ${featureId}`, 'Submarine');
   244→}
