   246→// ─────────────────────────────────────────────────────────────────────────────
   247→// WAVE EXECUTION
   248→// ─────────────────────────────────────────────────────────────────────────────
   249→
   250→async function executeWave(waveNum: number): Promise<void> {
   251→  const wave = waves.find((w) => w.wave === waveNum);
   252→  if (!wave) {
   253→    printError(`Wave ${waveNum} not found`);
   254→    return;
   255→  }
   256→
   257→  printHeader(`🌊 WAVE ${wave.wave}: ${wave.description}`);
   258→
   259→  // Check dependencies
   260→  if (wave.dependsOn !== null) {
   261→    const prevWave = waves.find((w) => w.wave === wave.dependsOn);
   262→    if (prevWave) {
   263→      const prevFeatures = prevWave.groups.flatMap((g) => g.features);
   264→      for (const f of prevFeatures) {
   265→        const status = await getFeatureStatus(f.id);
   266→        if (status !== 'complete') {
   267→          printError(`Wave ${waveNum} blocked: ${f.id} from Wave ${wave.dependsOn} is not complete`);
   268→          printInfo('Complete previous wave first, then run this wave.');
   269→          return;
   270→        }
   271→      }
   272→    }
   273→  }
   274→
   275→  print(`${c.dim}Max concurrency: ${wave.maxConcurrency}${c.reset}\n`);
   276→
   277→  // Process groups
   278→  const groupPromises: Promise<void>[] = [];
   279→
   280→  for (const group of wave.groups) {
   281→    groupPromises.push(executeGroup(group, wave.maxConcurrency));
   282→  }
   283→
   284→  // Wait for all groups in this wave
   285→  await Promise.all(groupPromises);
   286→
   287→  printSuccess(`Wave ${waveNum} initiated. Monitor each terminal for progress.`);
   288→  await notify('🌊 Wave Started', `Wave ${waveNum}: ${wave.groups.length} groups running`, 'Glass');
   289→}
   290→
   291→async function executeGroup(group: ParallelGroup, maxConcurrency: number): Promise<void> {
   292→  print(`\n${c.cyan}📦 Group: ${group.name}${c.reset}`);
   293→  print(`${c.dim}   Risk: ${group.conflictRisk} | Sequential: ${group.sequential}${c.reset}`);
   294→
   295→  if (group.sequential) {
   296→    // Sequential execution within group
   297→    printInfo('Features in this group run sequentially (same file conflicts)');
   298→
   299→    for (const feature of group.features) {
   300→      const status = await getFeatureStatus(feature.id);
   301→
   302→      if (status === 'complete') {
   303→        printSuccess(`${feature.id}: Already complete`);
   304→        continue;
   305→      }
   306→
   307→      if (status === 'in-progress') {
   308→        printWarning(`${feature.id}: Already in progress`);
   309→        continue;
   310→      }
   311→
   312→      // Create worktree and start session
   313→      const created = await createWorktree(feature.id);
   314→      if (created) {
   315→        const worktreePath = getWorktreePath(feature.id);
   316→        await startClaudeSession(feature.id, group.name, worktreePath);
   317→      }
   318→
   319→      // For sequential groups, we only start one at a time
   320→      // User must complete and merge before next starts
   321→      printInfo(`Complete ${feature.id}, merge to main, then run next feature in group.`);
   322→      break;
   323→    }
   324→  } else {
   325→    // Parallel execution within group
   326→    for (const feature of group.features) {
   327→      const status = await getFeatureStatus(feature.id);
   328→
   329→      if (status === 'complete') {
   330→        printSuccess(`${feature.id}: Already complete`);
   331→        continue;
   332→      }
   333→
   334→      if (status === 'in-progress') {
   335→        printWarning(`${feature.id}: Already in progress`);
   336→        continue;
   337→      }
   338→
   339→      // Create worktree and start session
   340→      const created = await createWorktree(feature.id);
   341→      if (created) {
   342→        const worktreePath = getWorktreePath(feature.id);
   343→        await startClaudeSession(feature.id, group.name, worktreePath);
   344→      }
   345→    }
   346→  }
   347→}
