   353→async function showStatus(): Promise<void> {
   354→  printHeader('📊 PARALLEL HARNESS STATUS');
   355→
   356→  const speedup = getEstimatedSpeedup();
   357→  print(`${c.cyan}Estimated speedup: ${speedup.speedup} (${speedup.sequential} sequential → ${speedup.parallel} parallel)${c.reset}\n`);
   358→
   359→  // Show worktrees
   360→  const worktrees = await listWorktrees();
   361→  print(`${c.bold}Active Worktrees:${c.reset}`);
   362→  for (const wt of worktrees) {
   363→    print(`  ${c.dim}${wt}${c.reset}`);
   364→  }
   365→
   366→  print('');
   367→
   368→  // Show wave status
   369→  for (const wave of waves) {
   370→    const waveStatus = wave.dependsOn
   371→      ? `${c.yellow}(blocked by Wave ${wave.dependsOn})${c.reset}`
   372→      : `${c.green}(ready)${c.reset}`;
   373→
   374→    print(`${c.bold}Wave ${wave.wave}: ${wave.description} ${waveStatus}${c.reset}`);
   375→
   376→    for (const group of wave.groups) {
   377→      print(`  ${c.cyan}├─ ${group.name}${c.reset} (${group.conflictRisk} risk)`);
   378→
   379→      for (const feature of group.features) {
   380→        const status = await getFeatureStatus(feature.id);
   381→        const statusIcon = status === 'complete' ? `${c.green}✓${c.reset}` : status === 'in-progress' ? `${c.yellow}⟳${c.reset}` : `${c.dim}○${c.reset}`;
   382→        print(`  │  ${statusIcon} ${feature.id}: ${feature.description}`);
   383→      }
   384→    }
   385→    print('');
   386→  }
   387→}
