   389→// ─────────────────────────────────────────────────────────────────────────────
   390→// CLEANUP
   391→// ─────────────────────────────────────────────────────────────────────────────
   392→
   393→async function cleanup(): Promise<void> {
   394→  printHeader('🧹 CLEANING UP WORKTREES');
   395→
   396→  const { stdout } = await runCommand('git', ['worktree', 'list']);
   397→  const lines = stdout.split('\n').filter(Boolean);
   398→
   399→  // Skip the main worktree
   400→  for (const line of lines.slice(1)) {
   401→    const path = line.split(/\s+/)[0];
   402→    if (path.includes('.trees/')) {
   403→      const featureId = path.split('/').pop()?.toUpperCase();
   404→      if (featureId) {
   405→        await removeWorktree(featureId);
   406→      }
   407→    }
   408→  }
   409→
   410→  // Remove .trees directory if empty
   411→  await runCommand('rm', ['-rf', '.trees']);
   412→
   413→  printSuccess('Cleanup complete');
   414→}
