   416→// ─────────────────────────────────────────────────────────────────────────────
   417→// MERGE HELPER
   418→// ─────────────────────────────────────────────────────────────────────────────
   419→
   420→async function mergeFeature(featureId: string): Promise<void> {
   421→  const branchName = getBranchName(featureId);
   422→  const worktreePath = getWorktreePath(featureId);
   423→
   424→  printHeader(`🔀 MERGING ${featureId}`);
   425→
   426→  // Check if feature is complete
   427→  const status = await getFeatureStatus(featureId);
   428→  if (status !== 'complete') {
   429→    printWarning(`Feature ${featureId} is not marked as complete in features.json`);
   430→    printInfo('Mark passes: true before merging.');
   431→    return;
   432→  }
   433→
   434→  // Switch to main and merge
   435→  printInfo('Switching to main branch...');
   436→  await runCommand('git', ['checkout', 'main']);
   437→
   438→  printInfo(`Merging ${branchName}...`);
   439→  const { exitCode, stderr } = await runCommand('git', ['merge', branchName, '--no-ff', '-m', `Merge ${branchName}: ${featureId}`]);
   440→
   441→  if (exitCode !== 0) {
   442→    printError(`Merge failed: ${stderr}`);
   443→    printInfo('Resolve conflicts manually, then run: git merge --continue');
   444→    return;
   445→  }
   446→
   447→  printSuccess(`Merged ${branchName} to main`);
   448→
   449→  // Remove worktree
   450→  await removeWorktree(featureId);
   451→
   452→  // Delete branch
   453→  await runCommand('git', ['branch', '-d', branchName]);
   454→
   455→  printSuccess(`Cleanup complete for ${featureId}`);
   456→  await notify('✅ Feature Merged', `${featureId} merged to main`, 'Glass');
   457→}
