   461→// ─────────────────────────────────────────────────────────────────────────────
   462→
   463→async function showMenu(): Promise<void> {
   464→  printHeader('🔧 MMS PARALLEL HARNESS RUNNER');
   465→
   466→  const speedup = getEstimatedSpeedup();
   467→  print(`${c.cyan}Estimated speedup: ${speedup.speedup}${c.reset}\n`);
   468→
   469→  print('Commands:');
   470→  print(`  ${c.green}1${c.reset}. Execute Wave 1 (Initial parallel)`);
   471→  print(`  ${c.green}2${c.reset}. Execute Wave 2 (Keyboard + Panel)`);
   472→  print(`  ${c.green}3${c.reset}. Execute Wave 3 (Accessibility)`);
   473→  print(`  ${c.green}4${c.reset}. Execute Wave 4 (ARIA labels)`);
   474→  print(`  ${c.yellow}s${c.reset}. Show status`);
   475→  print(`  ${c.yellow}c${c.reset}. Cleanup worktrees`);
   476→  print(`  ${c.yellow}m${c.reset}. Merge a feature`);
   477→  print(`  ${c.dim}q${c.reset}. Quit`);
   478→  print('');
   479→
   480→  process.stdout.write(`${c.bold}> ${c.reset}`);
   481→
   482→  const reader = Bun.stdin.stream().getReader();
   483→  const { value } = await reader.read();
   484→  reader.releaseLock();
   485→
   486→  if (!value) return;
   487→
   488→  const input = new TextDecoder().decode(value).trim().toLowerCase();
   489→
   490→  switch (input) {
   491→    case '1':
   492→      await executeWave(1);
   493→      break;
   494→    case '2':
   495→      await executeWave(2);
   496→      break;
   497→    case '3':
   498→      await executeWave(3);
   499→      break;
   500→    case '4':
   501→      await executeWave(4);
   502→      break;
   503→    case 's':
   504→      await showStatus();
   505→      break;
   506→    case 'c':
   507→      await cleanup();
   508→      break;
   509→    case 'm':
   510→      print('Enter feature ID to merge (e.g., F023): ');
   511→      const reader2 = Bun.stdin.stream().getReader();
   512→      const { value: val2 } = await reader2.read();
   513→      reader2.releaseLock();
   514→      if (val2) {
   515→        const featureId = new TextDecoder().decode(val2).trim().toUpperCase();
   516→        await mergeFeature(featureId);
